import os
from google.cloud import storage
import pickle

def get_latest_model(gcs_bucket, model_dir):
    client = storage.Client()
    blobs = list(client.list_blobs(bucket_or_name=gcs_bucket))
    
    latest_model_file = max([blob.name for blob in blobs if blob.name.startswith(model_dir)], key=lambda x: (int(x.split('/')[-1].split('-')[0]), int(x.split('/')[-1].split('-')[1])))
    return f"{model_dir}{latest_model_file}"

def load_latest_model_from_gcs(bucket_name, model_dir):
    latest_model_path = get_latest_model(bucket_name, model_dir)
    
    client = storage.Client()
    blob = client.blob(latest_model_path)
    blob.download_to_filename(f"temp_{latest_model_path}")
    
    with open(f"temp_{latest_model_path}", "rb") as f:
        model = pickle.load(f)
        
    os.remove(f"temp_{latest_model_path}")
    return model

def load_latest_model():
    bucket_name = 'your-bucket-name' # Replace with your GCS bucket name
    model_dir = os.environ.get('MODEL_PATH', '') # Fetch model path from env var
    
    if not model_dir:
        raise ValueError("MODEL_PATH environment variable is required")
    
    return load_latest_model_from_gcs(bucket_name, model_dir)

